    50→        this.requestTimeout = requestTimeout;
    51→    }
    52→
    53→    /**
    54→     * Wait for a {@link FutureCallback} to complete and return the result if successful.
    55→     * @param cb the future callback to wait for
    56→     * @return the future callback's result if successful
    57→     * @param <T> the future's result type
    58→     * @throws Throwable if the future callback isn't successful
