    60→    public <T> T completeRequest(FutureCallback<T> cb) throws Throwable {
    61→        try {
    62→            return cb.get(requestTimeout.timeoutMs(), TimeUnit.MILLISECONDS);
    63→        } catch (ExecutionException e) {
    64→            throw e.getCause();
    65→        } catch (StagedTimeoutException e) {
    66→            Stage stage = e.stage();
    67→            String message = "Request timed out. " + stage.summarize();
    68→            // This timeout is for the operation itself. None of the timeout error codes are relevant, so internal server
    69→            // error is the best option
    70→            throw new ConnectRestException(Response.Status.INTERNAL_SERVER_ERROR.getStatusCode(), message);
    71→        } catch (TimeoutException e) {
    72→            // This timeout is for the operation itself. None of the timeout error codes are relevant, so internal server
    73→            // error is the best option
    74→            throw new ConnectRestException(Response.Status.INTERNAL_SERVER_ERROR.getStatusCode(), "Request timed out");
    75→        } catch (InterruptedException e) {
    76→            throw new ConnectRestException(Response.Status.INTERNAL_SERVER_ERROR.getStatusCode(), "Request interrupted");
    77→        }
    78→    }
    79→
    80→    /**
