    82→     * request to the indicated target.
    83→     */
    84→    public <T, U> T completeOrForwardRequest(FutureCallback<T> cb,
    85→                                             String path,
    86→                                             String method,
    87→                                             HttpHeaders headers,
    88→                                             Map<String, String> queryParameters,
    89→                                             Object body,
    90→                                             TypeReference<U> resultType,
    91→                                             Translator<T, U> translator,
    92→                                             Boolean forward) throws Throwable {
    93→        try {
    94→            return completeRequest(cb);
    95→        } catch (RequestTargetException e) {
    96→            if (forward == null || forward) {
    97→                // the only time we allow recursive forwarding is when no forward flag has
    98→                // been set, which should only be seen by the first worker to handle a user request.
    99→                // this gives two total hops to resolve the request before giving up.
