   122→                // we don't, it probably means that a rebalance has taken place.
   123→                throw new ConnectRestException(Response.Status.CONFLICT.getStatusCode(),
   124→                        "Cannot complete request because of a conflicting operation (e.g. worker rebalance)");
   125→            }
